     1→package db
     2→
     3→import (
     4→	"context"
     5→	"database/sql"
     6→	"fmt"
     7→	"os"
     8→	"path/filepath"
     9→	"sort"
    10→	"strings"
    11→	"time"
    12→
    13→	"go.uber.org/zap"
    14→	_ "modernc.org/sqlite"
    15→)
    16→
    17→// DB wraps the database connection
    18→type DB struct {
    19→	*sql.DB
    20→	logger *zap.Logger
    21→}
    22→
    23→// Config holds database configuration
    24→type Config struct {
    25→	DBPath         string
    26→	MigrationsPath string
    27→}
    28→
    29→// New creates a new database connection and runs migrations
    30→func New(cfg Config, logger *zap.Logger) (*DB, error) {
    31→	// Ensure data directory exists
    32→	dataDir := filepath.Dir(cfg.DBPath)
    33→	if err := os.MkdirAll(dataDir, 0755); err != nil {
    34→		return nil, fmt.Errorf("failed to create data directory: %w", err)
    35→	}
    36→
    37→	// Open database connection
    38→	sqlDB, err := sql.Open("sqlite", cfg.DBPath)
    39→	if err != nil {
    40→		return nil, fmt.Errorf("failed to open database: %w", err)
    41→	}
    42→
    43→	// Configure connection pool
    44→	sqlDB.SetMaxOpenConns(1) // SQLite supports only one writer
    45→	sqlDB.SetMaxIdleConns(1)
    46→	sqlDB.SetConnMaxLifetime(time.Hour)
    47→
    48→	// Enable foreign keys and WAL mode for better concurrency
    49→	pragmas := []string{
    50→		"PRAGMA foreign_keys = ON",
    51→		"PRAGMA journal_mode = WAL",
    52→		"PRAGMA synchronous = NORMAL",
    53→		"PRAGMA busy_timeout = 5000",
    54→	}
    55→
    56→	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
    57→	defer cancel()
    58→
    59→	for _, pragma := range pragmas {
    60→		if _, err := sqlDB.ExecContext(ctx, pragma); err != nil {
    61→			sqlDB.Close()
    62→			return nil, fmt.Errorf("failed to execute %s: %w", pragma, err)
    63→		}
    64→	}
    65→
    66→	// Verify connection
    67→	if err := sqlDB.PingContext(ctx); err != nil {
    68→		sqlDB.Close()
    69→		return nil, fmt.Errorf("failed to ping database: %w", err)
    70→	}
    71→
    72→	db := &DB{DB: sqlDB, logger: logger}
    73→
    74→	// Run migrations
    75→	if cfg.MigrationsPath != "" {
    76→		if err := db.runMigrations(ctx, cfg.MigrationsPath); err != nil {
    77→			sqlDB.Close()
    78→			return nil, fmt.Errorf("failed to run migrations: %w", err)
    79→		}
    80→	}
    81→
    82→	logger.Info("Database initialized", zap.String("path", cfg.DBPath))
    83→	return db, nil
    84→}
    85→
    86→// runMigrations executes all pending SQL migration files
    87→func (db *DB) runMigrations(ctx context.Context, migrationsPath string) error {
    88→	// Create migrations table if it doesn't exist
    89→	createTableSQL := `
    90→		CREATE TABLE IF NOT EXISTS schema_migrations (
    91→			version TEXT PRIMARY KEY,
    92→			applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    93→		)
    94→	`
    95→	if _, err := db.ExecContext(ctx, createTableSQL); err != nil {
    96→		return fmt.Errorf("failed to create migrations table: %w", err)
    97→	}
    98→
    99→	// Get applied migrations
   100→	appliedMigrations := make(map[string]bool)
   101→	rows, err := db.QueryContext(ctx, "SELECT version FROM schema_migrations")
   102→	if err != nil {
   103→		return fmt.Errorf("failed to query migrations: %w", err)
   104→	}
   105→	defer rows.Close()
   106→
   107→	for rows.Next() {
   108→		var version string
   109→		if err := rows.Scan(&version); err != nil {
   110→			return fmt.Errorf("failed to scan migration version: %w", err)
   111→		}
   112→		appliedMigrations[version] = true
   113→	}
   114→	if err := rows.Err(); err != nil {
   115→		return fmt.Errorf("error iterating migrations: %w", err)
   116→	}
   117→
   118→	// Check if migrations directory exists
   119→	if _, err := os.Stat(migrationsPath); os.IsNotExist(err) {
   120→		db.logger.Warn("Migrations directory does not exist, skipping migrations",
   121→			zap.String("path", migrationsPath))
   122→		return nil
   123→	}
   124→
   125→	// Read migration files
   126→	files, err := os.ReadDir(migrationsPath)
   127→	if err != nil {
   128→		return fmt.Errorf("failed to read migrations directory: %w", err)
   129→	}
   130→
   131→	// Filter and sort .sql files
   132→	var migrationFiles []string
   133→	for _, file := range files {
   134→		if !file.IsDir() && strings.HasSuffix(file.Name(), ".sql") {
   135→			migrationFiles = append(migrationFiles, file.Name())
   136→		}
   137→	}
   138→	sort.Strings(migrationFiles)
   139→
   140→	// Apply pending migrations
   141→	for _, filename := range migrationFiles {
   142→		version := strings.TrimSuffix(filename, ".sql")
   143→
   144→		if appliedMigrations[version] {
   145→			continue
   146→		}
   147→
   148→		db.logger.Info("Applying migration", zap.String("file", filename))
   149→
   150→		// Read migration file
   151→		content, err := os.ReadFile(filepath.Join(migrationsPath, filename))
   152→		if err != nil {
   153→			return fmt.Errorf("failed to read migration %s: %w", filename, err)
   154→		}
   155→
   156→		// Execute migration in a transaction
   157→		tx, err := db.BeginTx(ctx, nil)
   158→		if err != nil {
