   177→		}
   178→
   179→		db.logger.Info("Migration applied successfully", zap.String("file", filename))
   180→	}
   181→
   182→	return nil
   183→}
   184→
   185→// Close closes the database connection
   186→func (db *DB) Close() error {
   187→	return db.DB.Close()
   188→}
   189→
   190→// HealthCheck verifies database connectivity
   191→func (db *DB) HealthCheck(ctx context.Context) error {
   192→	ctx, cancel := context.WithTimeout(ctx, 2*time.Second)
   193→	defer cancel()
   194→
   195→	return db.PingContext(ctx)
   196→}
