    69→// getEnv reads an environment variable or returns a default value
    70→func getEnv(key, defaultValue string) string {
    71→	if value := os.Getenv(key); value != "" {
    72→		return value
    73→	}
    74→	return defaultValue
    75→}
    76→
    77→// getEnvAsInt reads an environment variable as int or returns a default value
    78→func getEnvAsInt(key string, defaultValue int) int {
    79→	valueStr := os.Getenv(key)
    80→	if valueStr == "" {
    81→		return defaultValue
    82→	}
    83→	value, err := strconv.Atoi(valueStr)
    84→	if err != nil {
    85→		// Silently use default - logger not available yet during config load
    86→		return defaultValue
    87→	}
    88→	return value
    89→}
    90→
    91→// getEnvAsSlice reads an environment variable as comma-separated values
    92→func getEnvAsSlice(key string, defaultValue []string) []string {
    93→	valueStr := os.Getenv(key)
    94→	if valueStr == "" {
    95→		return defaultValue
    96→	}
    97→
    98→	var result []string
    99→	for _, v := range splitCommaSeparated(valueStr) {
   100→		if trimmed := trimSpace(v); trimmed != "" {
   101→			result = append(result, trimmed)
   102→		}
   103→	}
   104→
   105→	if len(result) == 0 {
   106→		return defaultValue
   107→	}
   108→	return result
   109→}
   110→
   111→// splitCommaSeparated splits a string by commas
   112→func splitCommaSeparated(s string) []string {
   113→	var parts []string
   114→	current := ""
   115→	for _, ch := range s {
   116→		if ch == ',' {
   117→			parts = append(parts, current)
   118→			current = ""
   119→		} else {
   120→			current += string(ch)
   121→		}
   122→	}
   123→	if current != "" {
   124→		parts = append(parts, current)
   125→	}
   126→	return parts
   127→}
   128→
   129→// trimSpace removes leading and trailing whitespace
   130→func trimSpace(s string) string {
   131→	start := 0
   132→	end := len(s)
   133→
   134→	for start < end && (s[start] == ' ' || s[start] == '\t' || s[start] == '\n' || s[start] == '\r') {
   135→		start++
   136→	}
   137→
   138→	for end > start && (s[end-1] == ' ' || s[end-1] == '\t' || s[end-1] == '\n' || s[end-1] == '\r') {
   139→		end--
   140→	}
   141→
   142→	return s[start:end]
   143→}
